# Shapes module with inheritance and interface implementations

from types import IHasArea, IDrawable, ShapeType, Point

class Shape(IHasArea):
    center: Point
    shape_type: ShapeType

    def __init__(self, center: Point, type: ShapeType):
        self.center = center
        self.shape_type = type

    @virtual
    property get area(self) -> float:
        return 0.0

    @virtual
    def get_description(self) -> str:
        return "Base shape"

    def get_type_name(self) -> str:
        return self.shape_type.name

class Circle(Shape, IDrawable):
    radius: float

    def __init__(self, center: Point, radius: float):
        super().__init__(center, ShapeType.CIRCLE)
        self.radius = radius

    @override
    property get area(self) -> float:
        return 3.14159 * self.radius * self.radius

    @override
    def get_description(self) -> str:
        return "Circle with radius " + str(self.radius)

    @override
    def draw(self) -> str:
        return "Drawing circle at (" + str(self.center.x) + ", " + str(self.center.y) + ")"

class Rectangle(Shape, IDrawable):
    width: float
    height: float

    def __init__(self, center: Point, width: float, height: float):
        super().__init__(center, ShapeType.RECTANGLE)
        self.width = width
        self.height = height

    @override
    property get area(self) -> float:
        return self.width * self.height

    @override
    def get_description(self) -> str:
        return "Rectangle " + str(self.width) + "x" + str(self.height)

    @override
    def draw(self) -> str:
        return "Drawing rectangle at (" + str(self.center.x) + ", " + str(self.center.y) + ")"
